import { GoogleGenAI, Type, Schema } from "@google/genai";
import { Opportunity } from "../types";

const SYSTEM_INSTRUCTION = `
You are MuternalAI, a Market Intelligence Engine.
Your goal is to detect high-potential SaaS opportunities by analyzing REAL-TIME signals via Google Search.

You must look for:
1. Demand: Rising search terms and questions.
2. Pain: Specific complaints on Reddit, forums, and communities.
3. Momentum: Buzz on Twitter/X and news.
4. Supply: Existing competitors on Product Hunt/G2.

SCORING RULES:
- Pain, Demand, Momentum: 1 (Low) to 10 (High).
- Supply: 1 (Empty) to 10 (Saturated).
- Opportunity Score Calculation: (Demand * Pain * Momentum) / Supply.
`;

export const generateOpportunities = async (niche: string = "General"): Promise<Opportunity[]> => {
  if (!process.env.API_KEY) {
    throw new Error("API Key is missing");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Perform a live market analysis for the SaaS niche: "${niche}".
    Use Google Search to find current data (last 90 days).

    Identify 4-6 specific, high-potential Micro-SaaS opportunities.

    For each opportunity, estimate the following based on search results:
    - Demand Growth: Estimate percentage growth (e.g., "+120%") based on trend descriptions.
    - Reddit Complaints: Estimate frequency of complaints found.
    - Twitter/Social Mentions: Estimate monthly discussion volume.
    - Competitor Count: Count notable direct competitors.

    Return the data strictly as a JSON array.
  `;

  const opportunitySchema: Schema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        opportunity_name: { type: Type.STRING },
        target_user: { type: Type.STRING },
        dominant_pain: { type: Type.STRING, description: "Specific problem statement found in search" },

        // Scores 1-10
        pain_score: { type: Type.NUMBER, description: "1-10 integer" },
        demand_score: { type: Type.NUMBER, description: "1-10 integer" },
        momentum_score: { type: Type.NUMBER, description: "1-10 integer. Viral potential." },
        supply_score: { type: Type.NUMBER, description: "1-10 integer. 1 is empty, 10 is saturated." },

        // Metrics
        demand_growth: { type: Type.STRING, description: "e.g. '+45%'" },
        reddit_complaints: { type: Type.NUMBER, description: "Estimated count of threads/complaints" },
        twitter_mentions: { type: Type.NUMBER, description: "Estimated mentions" },
        competitor_count: { type: Type.NUMBER, description: "Number of direct competitors" },

        opportunity_score: { type: Type.NUMBER, description: "Calculated score 0-100" },
        build_recommendation: { type: Type.STRING, description: "Specific technical or GTM advice." },
      },
      required: [
        "opportunity_name", "target_user", "dominant_pain", 
        "pain_score", "demand_score", "momentum_score", "supply_score",
        "demand_growth", "reddit_complaints", "twitter_mentions", "competitor_count",
        "opportunity_score", "build_recommendation"
      ],
    },
  };

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }], // Enable Live Grounding
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: opportunitySchema,
        temperature: 0.7,
      },
    });

    const text = response.text;
    if (!text) return [];

    const data = JSON.parse(text) as Opportunity[];

    // Client-side Re-scoring to ensure mathematical consistency with user's formula
    // Formula: (Demand * Pain * Momentum) / Supply
    // Normalization: The raw max is (10*10*10)/1 = 1000. We need to scale to 0-100.
    // A "Good" score is usually around 8*8*8 / 3 ~ 170. 
    // We will use a logarithmic-like scaling or simple clamping to make it readable.

    return data.map(opp => {
      // Raw calculation
      const numerator = opp.pain_score * opp.demand_score * opp.momentum_score;
      const denominator = Math.max(1, opp.supply_score); // Avoid divide by zero
      const rawScore = numerator / denominator;

      // Normalize: We treat a raw score of 200 as "100%". 
      // (10 * 10 * 10) / 5 = 200. This is a very strong signal.
      const normalizedScore = Math.min(100, Math.round((rawScore / 200) * 100));

      return {
        ...opp,
        opportunity_score: normalizedScore
      };
    }).sort((a, b) => b.opportunity_score - a.opportunity_score);

  } catch (error) {
    console.error("Analysis Failed:", error);
    throw error;
  }
};

import React from 'react';
import { ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, Cell } from 'recharts';
import { Opportunity } from '../types';

interface Props {
  opportunity: Opportunity;
}

const AnalysisChart: React.FC<Props> = ({ opportunity }) => {
  // Helper to determine color based on score value and type
  const getColor = (value: number, type: 'standard' | 'inverse') => {
    if (type === 'inverse') {
       // For Saturation/Supply: High score is BAD (Red), Low score is GOOD (Green)
       if (value >= 7) return '#F87171'; 
       if (value >= 4) return '#FACC15';
       return '#14F1A0';
    }

    // For Pain/Demand/Momentum: High score is GOOD (Green), Low score is BAD (Red)
    if (value >= 7) return '#14F1A0';
    if (value >= 4) return '#FACC15';
    return '#F87171';
  };

  const data = [
    { 
      name: 'Pain', 
      value: opportunity.pain_score, 
      color: getColor(opportunity.pain_score, 'standard') 
    },
    { 
      name: 'Demand', 
      value: opportunity.demand_score, 
      color: getColor(opportunity.demand_score, 'standard') 
    },
    { 
      name: 'Momentum', 
      value: opportunity.momentum_score, 
      color: getColor(opportunity.momentum_score, 'standard') 
    },
    { 
      name: 'Supply', 
      value: opportunity.supply_score, 
      color: getColor(opportunity.supply_score, 'inverse') 
    },
  ];

  return (
    <div className="h-48 w-full mt-4 bg-dark-surface rounded-lg p-2 border border-dark-border/50">
      <div className="text-xs text-gray-500 font-mono mb-2 uppercase tracking-wider">Metric Breakdown</div>
      <ResponsiveContainer width="100%" height="100%">
        <BarChart layout="vertical" data={data} margin={{ left: 0, right: 20, top: 0, bottom: 0 }}>
          <XAxis type="number" domain={[0, 10]} hide />
          <YAxis 
            dataKey="name" 
            type="category" 
            tick={{ fill: '#9ca3af', fontSize: 10, fontFamily: 'JetBrains Mono' }} 
            width={60} 
            axisLine={false}
            tickLine={false}
          />
          <Tooltip 
            cursor={{ fill: 'transparent' }}
            contentStyle={{ backgroundColor: '#18181b', borderColor: '#27272a', color: '#fff' }}
            itemStyle={{ fontFamily: 'JetBrains Mono', fontSize: '12px' }}
          />
          <Bar dataKey="value" radius={[0, 4, 4, 0]} barSize={16} background={{ fill: '#27272a' }}>
            {data.map((entry, index) => (
              <Cell key={`cell-${index}`} fill={entry.color} />
            ))}
          </Bar>
        </BarChart>
      </ResponsiveContainer>
    </div>
  );
};

export default AnalysisChart;

