}

export enum AppState {
  IDLE = 'IDLE',
  SCANNING = 'SCANNING',
  ANALYZING = 'ANALYZING',
  COMPLETE = 'COMPLETE',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { Opportunity } from "../types";

const SYSTEM_INSTRUCTION = `
You are MuternalAI, a Real-Time Intelligence Engine.
Your goal is to detect high-leverage SaaS opportunities by analyzing 4 key data sources.

DATA SOURCES & RULES:
1. Google Trends -> Demand Score (Search momentum).
2. Reddit -> Pain Score (Complaint frequency & intensity).
3. Twitter (X) -> Momentum Score (Engagement spikes & viral potential).
4. Product Hunt -> Saturation Score (Competitor count).

You must generate strictly numeric scores (0-10) for these four dimensions based on real search findings.
`;

export const generateOpportunities = async (niche: string = "General"): Promise<Opportunity[]> => {
  if (!process.env.API_KEY) {
    throw new Error("API Key is missing");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Analyze the SaaS niche: "${niche}" using Google Search to find real-time signals (last 90 days).

    Identify top 10 Micro-SaaS opportunities.

    For each opportunity, provide:
    1. Opportunity Name & Target User.
    2. Dominant Pain: A specific problem found in Reddit threads.
    3. Scores (0-10):
       - Demand Score: Based on Google Trends search volume/growth.
       - Pain Score: Based on Reddit complaint severity.
       - Momentum Score: Based on Twitter/X discussion velocity.
       - Saturation Score: Based on Product Hunt competitor density (10 = High Saturation/Many Competitors, 0 = Blue Ocean).
    4. Metrics:
       - Demand Growth: String (e.g. "+145%").
       - Reddit Complaints: Estimated count.
       - Twitter Mentions: Estimated count.
       - Competitor Count: Count of direct rivals.
    5. Demand Locations:
       - Identify 3-5 global cities/regions where search interest is highest.
       - Provide approximate Latitude/Longitude for these cities.
       - Assign an intensity (1-10) for the heat map.

    Return the data strictly as a JSON array.
  `;

  const opportunitySchema: Schema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        opportunity_name: { type: Type.STRING },
        target_user: { type: Type.STRING },
        dominant_pain: { type: Type.STRING, description: "Specific problem statement found in search" },

        // Scores 0-10
        pain_score: { type: Type.NUMBER, description: "0-10 integer based on Reddit" },
        demand_score: { type: Type.NUMBER, description: "0-10 integer based on Google Trends" },
        momentum_score: { type: Type.NUMBER, description: "0-10 integer based on Twitter" },
        supply_score: { type: Type.NUMBER, description: "0-10 integer based on Product Hunt (Saturation)" },

        // Metrics
        demand_growth: { type: Type.STRING, description: "e.g. '+45%'" },
        reddit_complaints: { type: Type.NUMBER, description: "Estimated count of threads/complaints" },
        twitter_mentions: { type: Type.NUMBER, description: "Estimated mentions" },
        competitor_count: { type: Type.NUMBER, description: "Number of direct competitors" },

        build_recommendation: { type: Type.STRING, description: "Specific technical or GTM advice." },

        // Geolocation
        demand_locations: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              city: { type: Type.STRING },
              country: { type: Type.STRING },
              lat: { type: Type.NUMBER },
              lng: { type: Type.NUMBER },
              intensity: { type: Type.NUMBER, description: "1-10 heat intensity" }
            }
          }
        }
      },
      required: [
        "opportunity_name", "target_user", "dominant_pain", 
        "pain_score", "demand_score", "momentum_score", "supply_score",
        "demand_growth", "reddit_complaints", "twitter_mentions", "competitor_count",
        "build_recommendation", "demand_locations"
      ],
    },
  };

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }], 
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: opportunitySchema,
        temperature: 0.7,
      },
    });

    const text = response.text;
    if (!text) return [];

    const data = JSON.parse(text) as Omit<Opportunity, 'opportunity_score'>[];

    // Client-side Scoring Engine
    // Formula: (Demand * 0.35) + (Pain * 0.25) + (Momentum * 0.25) - (Saturation * 0.15)
    // Multiply by 10 for 0-100 scale.

    return data.map(opp => {
      // Ensure saturation is treated as a penalty
      const demandWeighted = opp.demand_score * 0.35;
      const painWeighted = opp.pain_score * 0.25;
      const momentumWeighted = opp.momentum_score * 0.25;
      const saturationPenalty = opp.supply_score * 0.15;

      const rawScore = (demandWeighted + painWeighted + momentumWeighted) - saturationPenalty;

      // Calculate final and clamp between 0-100 just in case
      let finalScore = Math.round(rawScore * 10);
      finalScore = Math.max(0, Math.min(100, finalScore));

      return {
        ...opp,
        opportunity_score: finalScore
      };
    }).sort((a, b) => b.opportunity_score - a.opportunity_score); // Sort by highest score

  } catch (error) {
    console.error("Analysis Failed:", error);
    throw error;
  }
};

