  const getConfidence = (opp: Opportunity) => {
     // Higher scores + lower supply = higher confidence
     const base = opp.opportunity_score;
     const supplyBonus = (10 - opp.supply_score) * 2;
     return Math.min(99, Math.round(base + supplyBonus * 0.5));
  };

