const SIGNALS = [
  "Scanning r/SaaS for complaints...",
  "Analyzing 'How to automate' queries on Google Trends...",
  "Parsing Product Hunt launches from last 30 days...",
  "Detecting saturation in 'Copywriting AI'...",
  "High demand signal: 'AI Legal Compliance'...",
  "User frustration detected: 'QuickBooks API integration'...",
  "Calculating pain scores for Vertical SaaS...",
  "Indexing G2 Crowd negative reviews...",
  "Synthesizing market gaps..."
];

const SignalStream: React.FC<{ active: boolean }> = ({ active }) => {
  const [lines, setLines] = useState<string[]>([]);

  useEffect(() => {
    if (!active) {
      setLines([]);
      return;
    }

    let index = 0;
    const interval = setInterval(() => {
      setLines(prev => {
        const newLine = `[${new Date().toISOString().split('T')[1].slice(0,8)}] > ${SIGNALS[index % SIGNALS.length]}`;
        const newLines = [...prev, newLine];
        if (newLines.length > 5) newLines.shift();
        return newLines;
      });
      index++;
    }, 600);

    return () => clearInterval(interval);
  }, [active]);

  if (!active && lines.length === 0) return null;

  return (
    <div className="w-full bg-dark-bg/50 border-y border-brand-900/30 p-4 font-mono text-xs text-brand-400/80 overflow-hidden h-32 relative">
      <div className="absolute top-0 right-0 p-2 text-[10px] text-brand-600 uppercase">Live Feed</div>
      <div className="flex flex-col justify-end h-full space-y-1">
        {lines.map((line, i) => (
          <div key={i} className="animate-pulse">{line}</div>
        ))}
      </div>
    </div>
  );
};

