const SIGNALS = [
  "Gathering proof from r/SaaS complaints...",
  "Validating 'How to automate' queries...",
  "Analyzing startup launches...",
  "Detecting market gaps in 'Copywriting AI'...",
  "High demand validation: 'AI Legal Compliance'...",
